-- Insert 22 new reaction-time exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Random Gate Acceleration', 'random-gate-acceleration', 'The athlete waits for a live cue (coach names or points to gate), selects the correct answer, performs the movement response, and resets before the next rep. The rep counts only when the athlete reacts to the real stimulus rather than guessing early.', 'INTERMEDIATE', 8, 4, 4, 8, 60, 68, 'Random Gate Acceleration is a reaction-time-reduction drill for gate-choice acceleration without pre-planned direction. Use it when the goal is faster stimulus recognition, cleaner first movement, and safer reset behavior without turning reaction work into conditioning.', 'Primary subrole: reactive_agility_output. Coach Random Gate Acceleration as a quality-first reaction drill: define the cue, remove ambiguous starts, require a clean answer, and rest long enough that speed, accuracy, posture, and safety stay intact.', 'See the cue, answer fast, finish clean, then reset. Do not guess before the signal.', 'Simple Cue Response & Start Reaction', 'output', 'reactive_agility_tumbling_output', 'random_gate_acceleration', '{"stimulus":"coach names or points to gate","decision_pattern":"accelerate through the correct gate","space_needed":"Clear lane, small grid, or box with safe stopping room and no crossing traffic.","setup":"Mark start, finish/reset area, and any target lanes. Explain valid cues and decoy cues before the first rep. Rehearse once at low speed, then randomize the cue.","primary_joint_actions":["hip_flexion_extension","ankle_stiffness","trunk_bracing"],"primary_tissues":["calves","quadriceps","glutes","adductors","core"],"primary_motor_control_demands":["stimulus_discrimination","response_inhibition","first_step_timing","postural_reset"],"postural_shape":null,"breathing_demand":"brief brace with relaxed reset breathing","balance_demand":"dynamic balance during reaction and reset","coordination_demand":"high cue-to-action coordination","impact_level":2,"quality_gate":"Rep counts only when the athlete waits for the valid cue, chooses correctly, moves with control, brakes or catches safely, and resets posture before the next cue.","stop_signs":["false starts or guessing increase","wrong-direction responses repeat","posture, landing, catch, or braking quality drops","spacing becomes unsafe","pain, dizziness, panic, or symptom increase appears"],"reaction_time_reduction_target":{"stimulus":"coach names or points to gate","decisionPattern":"accelerate through the correct gate","primaryLatencyTarget":"shorten the time from valid cue recognition to first organized movement","secondaryTargets":["reduce false starts and guessing","improve first-step direction accuracy","improve braking or catch timing after the response","preserve posture and spacing while reacting"],"measurementIdeas":["track correct responses out of total cues","track false starts or wrong-direction responses","use video or timer when precise latency measurement is needed","progress only when accuracy stays high at the current speed"]}}'::jsonb, '{"movement_description":"Random Gate Acceleration: the athlete responds to coach names or points to gate with the required answer: accelerate through the correct gate.","setup":["Create a clear start position and target area.","Define the valid cue and any decoy cues.","Use enough spacing that a wrong response does not create collision risk.","Give one low-speed rehearsal before randomized reps."],"execution_steps":["Athlete sets posture and waits without pre-loading into the answer.","Coach or partner gives the cue at an unpredictable time.","Athlete reacts only to the valid cue and completes the movement response.","Athlete brakes, catches, or finishes safely.","Athlete resets breathing, stance, and attention before the next cue."],"breathing_cues":["Breathe quietly before the cue.","Exhale during the reset, not during the wait as a false trigger.","Avoid breath-holding across repeated cues."],"coach_cues":["Wait for information.","First step answers the cue.","Fast eyes, quiet body.","Brake before the next rep.","Reset so the next rep is real."],"athlete_cues":["Do not guess.","See it, then go.","Clean finish.","Reset your eyes and feet."],"quality_gate":["At least 80-90% correct responses at the chosen speed before progression.","No unsafe collisions, stumbles, or uncontrolled finishes.","Response quality stays crisp across the set."],"common_faults":["jumping early before the cue","turning the drill into a race or conditioning station","adding too many cue choices too soon","late braking or unsafe spacing","looking at the coach instead of the relevant target when scanning is required"],"stop_signs":["false starts or wrong choices stack up","athlete cannot explain the cue rule","mechanics degrade from fatigue","pain or symptoms appear"]}'::jsonb),
  ('Color Cone Touch on Call', 'color-cone-touch-on-call', 'The athlete waits for a live cue (coach calls cone color), selects the correct answer, performs the movement response, and resets before the next rep. The rep counts only when the athlete reacts to the real stimulus rather than guessing early.', 'BEGINNER', 8, 2, 6, 15, 30, 45, 'Color Cone Touch on Call is a reaction-time-reduction drill for simple color discrimination with short-range movement. Use it when the goal is faster stimulus recognition, cleaner first movement, and safer reset behavior without turning reaction work into conditioning.', 'Primary subrole: perception_action_reactive_movement. Coach Color Cone Touch on Call as a quality-first reaction drill: define the cue, remove ambiguous starts, require a clean answer, and rest long enough that speed, accuracy, posture, and safety stay intact.', 'See the cue, answer fast, finish clean, then reset. Do not guess before the signal.', 'Simple Cue Response & Start Reaction', 'movement_intelligence', 'perception_action_reactive_movement', 'color_cone_touch_on_call', '{"stimulus":"coach calls cone color","decision_pattern":"touch correct cone and return to base","space_needed":"Clear lane, small grid, or box with safe stopping room and no crossing traffic.","setup":"Mark start, finish/reset area, and any target lanes. Explain valid cues and decoy cues before the first rep. Rehearse once at low speed, then randomize the cue.","primary_joint_actions":["hip_flexion_extension","ankle_stiffness","trunk_bracing"],"primary_tissues":["calves","quadriceps","glutes","adductors","core"],"primary_motor_control_demands":["stimulus_discrimination","response_inhibition","first_step_timing","postural_reset"],"postural_shape":null,"breathing_demand":"brief brace with relaxed reset breathing","balance_demand":"dynamic balance during reaction and reset","coordination_demand":"high cue-to-action coordination","impact_level":1,"quality_gate":"Rep counts only when the athlete waits for the valid cue, chooses correctly, moves with control, brakes or catches safely, and resets posture before the next cue.","stop_signs":["false starts or guessing increase","wrong-direction responses repeat","posture, landing, catch, or braking quality drops","spacing becomes unsafe","pain, dizziness, panic, or symptom increase appears"],"reaction_time_reduction_target":{"stimulus":"coach calls cone color","decisionPattern":"touch correct cone and return to base","primaryLatencyTarget":"shorten the time from valid cue recognition to first organized movement","secondaryTargets":["reduce false starts and guessing","improve first-step direction accuracy","improve braking or catch timing after the response","preserve posture and spacing while reacting"],"measurementIdeas":["track correct responses out of total cues","track false starts or wrong-direction responses","use video or timer when precise latency measurement is needed","progress only when accuracy stays high at the current speed"]}}'::jsonb, '{"movement_description":"Color Cone Touch on Call: the athlete responds to coach calls cone color with the required answer: touch correct cone and return to base.","setup":["Create a clear start position and target area.","Define the valid cue and any decoy cues.","Use enough spacing that a wrong response does not create collision risk.","Give one low-speed rehearsal before randomized reps."],"execution_steps":["Athlete sets posture and waits without pre-loading into the answer.","Coach or partner gives the cue at an unpredictable time.","Athlete reacts only to the valid cue and completes the movement response.","Athlete brakes, catches, or finishes safely.","Athlete resets breathing, stance, and attention before the next cue."],"breathing_cues":["Breathe quietly before the cue.","Exhale during the reset, not during the wait as a false trigger.","Avoid breath-holding across repeated cues."],"coach_cues":["Wait for information.","First step answers the cue.","Fast eyes, quiet body.","Brake before the next rep.","Reset so the next rep is real."],"athlete_cues":["Do not guess.","See it, then go.","Clean finish.","Reset your eyes and feet."],"quality_gate":["At least 80-90% correct responses at the chosen speed before progression.","No unsafe collisions, stumbles, or uncontrolled finishes.","Response quality stays crisp across the set."],"common_faults":["jumping early before the cue","turning the drill into a race or conditioning station","adding too many cue choices too soon","late braking or unsafe spacing","looking at the coach instead of the relevant target when scanning is required"],"stop_signs":["false starts or wrong choices stack up","athlete cannot explain the cue rule","mechanics degrade from fatigue","pain or symptoms appear"]}'::jsonb),
  ('Clap-Cue Drop Step', 'clap-cue-drop-step', 'The athlete waits for a live cue (single clap or verbal side call), selects the correct answer, performs the movement response, and resets before the next rep. The rep counts only when the athlete reacts to the real stimulus rather than guessing early.', 'INTERMEDIATE', 8, 4, 4, 8, 60, 68, 'Clap-Cue Drop Step is a reaction-time-reduction drill for fast hip turn and drop-step reaction from an athletic stance. Use it when the goal is faster stimulus recognition, cleaner first movement, and safer reset behavior without turning reaction work into conditioning.', 'Primary subrole: acceleration_start_speed. Coach Clap-Cue Drop Step as a quality-first reaction drill: define the cue, remove ambiguous starts, require a clean answer, and rest long enough that speed, accuracy, posture, and safety stay intact.', 'See the cue, answer fast, finish clean, then reset. Do not guess before the signal.', 'Simple Cue Response & Start Reaction', 'output', 'acceleration_start_speed', 'clap_cue_drop_step', '{"stimulus":"single clap or verbal side call","decision_pattern":"drop step and drive in the cued direction","space_needed":"Clear lane, small grid, or box with safe stopping room and no crossing traffic.","setup":"Mark start, finish/reset area, and any target lanes. Explain valid cues and decoy cues before the first rep. Rehearse once at low speed, then randomize the cue.","primary_joint_actions":["hip_flexion_extension","ankle_stiffness","trunk_bracing"],"primary_tissues":["calves","quadriceps","glutes","adductors","core"],"primary_motor_control_demands":["stimulus_discrimination","response_inhibition","first_step_timing","postural_reset"],"postural_shape":null,"breathing_demand":"brief brace with relaxed reset breathing","balance_demand":"dynamic balance during reaction and reset","coordination_demand":"high cue-to-action coordination","impact_level":2,"quality_gate":"Rep counts only when the athlete waits for the valid cue, chooses correctly, moves with control, brakes or catches safely, and resets posture before the next cue.","stop_signs":["false starts or guessing increase","wrong-direction responses repeat","posture, landing, catch, or braking quality drops","spacing becomes unsafe","pain, dizziness, panic, or symptom increase appears"],"reaction_time_reduction_target":{"stimulus":"single clap or verbal side call","decisionPattern":"drop step and drive in the cued direction","primaryLatencyTarget":"shorten the time from valid cue recognition to first organized movement","secondaryTargets":["reduce false starts and guessing","improve first-step direction accuracy","improve braking or catch timing after the response","preserve posture and spacing while reacting"],"measurementIdeas":["track correct responses out of total cues","track false starts or wrong-direction responses","use video or timer when precise latency measurement is needed","progress only when accuracy stays high at the current speed"]}}'::jsonb, '{"movement_description":"Clap-Cue Drop Step: the athlete responds to single clap or verbal side call with the required answer: drop step and drive in the cued direction.","setup":["Create a clear start position and target area.","Define the valid cue and any decoy cues.","Use enough spacing that a wrong response does not create collision risk.","Give one low-speed rehearsal before randomized reps."],"execution_steps":["Athlete sets posture and waits without pre-loading into the answer.","Coach or partner gives the cue at an unpredictable time.","Athlete reacts only to the valid cue and completes the movement response.","Athlete brakes, catches, or finishes safely.","Athlete resets breathing, stance, and attention before the next cue."],"breathing_cues":["Breathe quietly before the cue.","Exhale during the reset, not during the wait as a false trigger.","Avoid breath-holding across repeated cues."],"coach_cues":["Wait for information.","First step answers the cue.","Fast eyes, quiet body.","Brake before the next rep.","Reset so the next rep is real."],"athlete_cues":["Do not guess.","See it, then go.","Clean finish.","Reset your eyes and feet."],"quality_gate":["At least 80-90% correct responses at the chosen speed before progression.","No unsafe collisions, stumbles, or uncontrolled finishes.","Response quality stays crisp across the set."],"common_faults":["jumping early before the cue","turning the drill into a race or conditioning station","adding too many cue choices too soon","late braking or unsafe spacing","looking at the coach instead of the relevant target when scanning is required"],"stop_signs":["false starts or wrong choices stack up","athlete cannot explain the cue rule","mechanics degrade from fatigue","pain or symptoms appear"]}'::jsonb),
  ('Light / Visual Cue Sprint Start', 'light-visual-cue-sprint-start', 'The athlete waits for a live cue (light flash or visual signal), selects the correct answer, performs the movement response, and resets before the next rep. The rep counts only when the athlete reacts to the real stimulus rather than guessing early.', 'INTERMEDIATE', 8, 4, 4, 8, 60, 68, 'Light / Visual Cue Sprint Start is a reaction-time-reduction drill for pure visual reaction start with reduced coach timing bias. Use it when the goal is faster stimulus recognition, cleaner first movement, and safer reset behavior without turning reaction work into conditioning.', 'Primary subrole: acceleration_start_speed. Coach Light / Visual Cue Sprint Start as a quality-first reaction drill: define the cue, remove ambiguous starts, require a clean answer, and rest long enough that speed, accuracy, posture, and safety stay intact.', 'See the cue, answer fast, finish clean, then reset. Do not guess before the signal.', 'Simple Cue Response & Start Reaction', 'output', 'acceleration_start_speed', 'light_visual_cue_sprint_start', '{"stimulus":"light flash or visual signal","decision_pattern":"sprint only when target cue appears","space_needed":"Clear lane, small grid, or box with safe stopping room and no crossing traffic.","setup":"Mark start, finish/reset area, and any target lanes. Explain valid cues and decoy cues before the first rep. Rehearse once at low speed, then randomize the cue.","primary_joint_actions":["hip_flexion_extension","ankle_stiffness","trunk_bracing"],"primary_tissues":["calves","quadriceps","glutes","adductors","core"],"primary_motor_control_demands":["stimulus_discrimination","response_inhibition","first_step_timing","postural_reset"],"postural_shape":null,"breathing_demand":"brief brace with relaxed reset breathing","balance_demand":"dynamic balance during reaction and reset","coordination_demand":"high cue-to-action coordination","impact_level":2,"quality_gate":"Rep counts only when t