INSERT INTO coaching.exercise_regimen_rule (
  exercise_id, can_be_daily, weekly_max_frequency, minimum_hours_between_hard_exposures,
  counts_as_high_intensity, counts_as_high_impact, counts_as_neural, counts_as_tissue_stress, counts_as_conditioning
)
SELECT e.id,
  COALESCE(m.can_be_daily, FALSE),
  COALESCE(m.weekly_max_frequency, 2),
  COALESCE(m.minimum_hours_between_hard_exposures, 48),
  COALESCE(m.counts_as_high_intensity, TRUE),
  COALESCE(m.counts_as_high_impact, FALSE),
  COALESCE(m.counts_as_neural, TRUE),
  COALESCE(m.counts_as_tissue_stress, TRUE),
  COALESCE(m.counts_as_conditioning, FALSE)
FROM (VALUES
  ('random-gate-acceleration', FALSE, 2, 48, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('color-cone-touch-on-call', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('clap-cue-drop-step', FALSE, 2, 48, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('light-visual-cue-sprint-start', FALSE, 2, 48, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('whistle-to-decel-stick', FALSE, 2, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('single-hand-tennis-ball-drop-catch', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('high-low-catch-decision-drill', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('reactive-y-cut', FALSE, 2, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('lateral-shuffle-decel-stick-on-cue', FALSE, 2, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('backpedal-to-sprint-turn-on-signal', FALSE, 2, 48, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('drop-step-crossover-go-on-cue', FALSE, 2, 48, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('reactive-5-10-5-finish-on-signal', FALSE, 2, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('reactive-hop-to-cut', FALSE, 2, 48, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('multi-cone-scan-and-go', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('bear-to-crab-switch-on-cue', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('low-line-partner-tag', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('boundary-recovery-drill', TRUE, 4, 24, FALSE, TRUE, TRUE, TRUE, FALSE),
  ('blind-side-shoulder-check-to-move', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('three-sixty-awareness-catch-with-safe-twist', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('small-sided-keep-away-footwork', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE),
  ('collision-avoidance-lane-change', TRUE, 4, 24, FALSE, TRUE, TRUE, TRUE, FALSE),
  ('low-speed-chaos-box-reset', TRUE, 4, 24, FALSE, FALSE, TRUE, FALSE, FALSE)
) AS m(slug, can_be_daily, weekly_max_frequency, minimum_hours_between_hard_exposures, counts_as_high_intensity, counts_as_high_impact, counts_as_neural, counts_as_tissue_stress, counts_as_conditioning)
JOIN coaching.exercise e ON e.slug = m.slug
WHERE NOT EXISTS (SELECT 1 FROM coaching.exercise_regimen_rule r WHERE r.exercise_id = e.id);

INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
SELECT e.id, 'youth_beginner', 'youth beginner', 'baseline', v.guidance,
  CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
FROM (VALUES
  ('random-gate-acceleration', 'Use one cue and one movement answer. Keep distance short, make it playful but not chaotic, and stop when attention or accuracy drops.', 'No default gender-specific adjustment. Individualize by training age, injury history, confidence with reactive work, pelvic-floor or abdominal-pressure symptoms, joint laxity, fatigue state, and sport demand.'),
  ('color-cone-touch-on-call', 'Use one cue and one movement answer. Keep distance short, make it playful but not chaotic, and stop when attention or accuracy drops.', 'No default gender-specific adjustment. Individualize by training age, injury history, confidence with reactive work, pelvic-floor or abdominal-pressure symptoms, joint laxity, fatigue state, and sport demand.'),
  ('clap-cue-drop-step', 'Use one cue and one movement answer. Keep distance short, make it playful but not chaotic, and stop when attention or accuracy drops.', 'No default gender-specific adjustment. Individualize by training age, injury history, confidence with reactive work, pelvic-floor or abdominal-pressure symptoms, joint laxity, fatigue state, and sport demand.'),
  ('light-visual-cue-sprint-start', 'Use one cue and one movement answer. Keep distance short, make it playful but not chaotic, and stop when attention or accuracy drops.', 'No default gender-specific adjustment. Individualize by training age, injury history, confidence with reactive work, pelvic-floor or abdominal-pressure symptoms, joint laxity, fatigue state, and sport demand.'),
